// Get simulated current price (slight random variation from base)
export function getSimulatedPrice(basePrice) {
    const variation = (Math.random() - 0.5) * 0.02 * basePrice;
    return basePrice + variation;
}

// Get holdings from localStorage
export function getHoldings(userId) {
    try {
        const saved = localStorage.getItem(`fc_holdings_${userId}`);
        return saved ? JSON.parse(saved) : {};
    } catch {
        return {};
    }
}

// Save holdings to localStorage
export function saveHoldings(userId, holdings) {
    localStorage.setItem(`fc_holdings_${userId}`, JSON.stringify(holdings));
}

// Get % change (simulated)
export function getDailyChange(symbol) {
    // Use a seeded-ish approach so it's consistent per session
    const seed = symbol.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
    const change = ((Math.sin(seed + Date.now() / 86400000) * 50) % 5);
    return Math.round(change * 100) / 100;
}
